import{_ as t,o,c as n,ag as a}from"./chunks/framework.6ZJjlmu_.js";const m=JSON.parse('{"title":"Invoke timing","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/invoke-timing.md","filePath":"how-to/invoke-timing.md"}'),i={name:"how-to/invoke-timing.md"};function r(s,e,l,d,c,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="invoke-timing" tabindex="-1">Invoke timing <a class="header-anchor" href="#invoke-timing" aria-label="Permalink to &quot;Invoke timing&quot;">​</a></h1><p><strong>Goal:</strong> Measure how long each event invocation takes (all handlers combined) and surface slow events in the Stats tab.</p><h2 id="enable-timing" tabindex="-1">Enable timing <a class="header-anchor" href="#enable-timing" aria-label="Permalink to &quot;Enable timing&quot;">​</a></h2><ol><li>Open <strong>Window → Event Monitor</strong>.</li><li>Toggle <strong>⏱ Timing</strong> in the toolbar (persisted across Editor restarts).</li><li>Enter Play Mode and trigger instrumented events.</li></ol><p>Timing is <strong>runtime-gated</strong> — no script recompile is required when toggling the setting.</p><h2 id="what-gets-measured" tabindex="-1">What gets measured <a class="header-anchor" href="#what-gets-measured" aria-label="Permalink to &quot;What gets measured&quot;">​</a></h2><p>IL Post Processing injects <code>BeginInvokeTiming</code> / <code>EndInvokeTiming</code> around each instrumented <code>Invoke()</code> call site. Duration is stored on the INVOKE record as <code>DurationMs</code>.</p><p>When enabled, Unity Profiler shows markers named <code>EventMonitor.&lt;EventName&gt;</code>.</p><h2 id="where-to-see-results" tabindex="-1">Where to see results <a class="header-anchor" href="#where-to-see-results" aria-label="Permalink to &quot;Where to see results&quot;">​</a></h2><ul><li><strong>Log → Detail panel</strong> — duration line on INVOKE rows with timing data.</li><li><strong>Stats tab</strong> — <strong>Slowest events (avg invoke duration)</strong> bar chart (top 10).</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Measures <strong>total invoke time</strong> for all handlers in one multicast call, not per-handler breakdown.</li><li>Null-conditional <code>?.Invoke()</code> with no subscribers may not be instrumented (no <code>Invoke</code> opcode).</li><li>Very short invokes may round to <code>0.00 ms</code> in the UI.</li></ul><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../concepts/ilpp-vs-reflection-scanner.html">ILPP vs Reflection Scanner</a></li><li><a href="./../reference/il-limitations.html">IL limitations</a></li></ul>',14)])])}const u=t(i,[["render",r]]);export{m as __pageData,u as default};
